/**
 * @brief Calculate CRC for a data buffer
 * @param data Pointer to data buffer
 * @param size Size of data in bytes
 * @param crc Pointer to store calculated CRC value
 * @return HAL_StatusTypeDef HAL status
 */
HAL_StatusTypeDef CRC_Calculate(const uint8_t *data, uint32_t size, uint32_t *crc)
{
    if (data == NULL || crc == NULL || size == 0) {
        CRC_ErrorHandler(CRC_ERROR_INVALID_PARAM);
        return HAL_ERROR;
    }

    if (size > CRC_MAX_DATA_SIZE_BYTES) {
        CRC_ErrorHandler(CRC_ERROR_DATA_SIZE);
        return HAL_ERROR;
    }

    if (!crc_status.initialized) {
        CRC_ErrorHandler(CRC_ERROR_INVALID_PARAM);
        return HAL_ERROR;
    }

    /* Calculate CRC based on method */
    if (current_config.method == CRC_METHOD_HARDWARE) {
        *crc = CRC_CalculateSoftware(data, size);
        crc_status.hardware_usage_count++;
    } else {
        *crc = CRC_CalculateSoftware(data, size);
        crc_status.software_usage_count++;
    }

    /* Apply XOR if configured */
    if (current_config.xor_output) {
        *crc ^= current_config.xor_value;
    }

    /* Store result */
    crc_status.last_calculated_crc = *crc;
    crc_status.calculation_count++;

    /* Call completion callback if registered */
    if (complete_callback != NULL) {
        complete_callback(*crc);
    }

    return HAL_OK;
}

