/**
 * @brief Accumulate CRC calculation (process data in chunks)
 * @param data Pointer to data buffer
 * @param size Size of data in bytes
 * @param crc Pointer to current CRC value (updated)
 * @return HAL_StatusTypeDef HAL status
 */
HAL_StatusTypeDef CRC_Accumulate(const uint8_t *data, uint32_t size, uint32_t *crc)
{
    if (data == NULL || crc == NULL || size == 0) {
        CRC_ErrorHandler(CRC_ERROR_INVALID_PARAM);
        return HAL_ERROR;
    }

    if (!crc_status.initialized) {
        CRC_ErrorHandler(CRC_ERROR_INVALID_PARAM);
        return HAL_ERROR;
    }

    /* For hardware method, use accumulate function */
    if (current_config.method == CRC_METHOD_HARDWARE) {
        /* Convert byte data to words for hardware CRC */
        uint32_t word_count = (size + 3) / 4;
        uint32_t temp_data[CRC_MAX_DATA_SIZE / 4];

        /* Copy data and pad if necessary */
        memset(temp_data, 0, sizeof(temp_data));
        memcpy(temp_data, data, size);

        *crc = HAL_CRC_Accumulate(&hcrc, temp_data, word_count);
        crc_status.hardware_usage_count++;
    } else {
        /* Software accumulation - XOR with current CRC */
        uint32_t new_crc = CRC_CalculateSoftware(data, size);
        *crc ^= new_crc;
        crc_status.software_usage_count++;
    }

    /* Apply XOR if configured */
    if (current_config.xor_output) {
        *crc ^= current_config.xor_value;
    }

    /* Store result */
    crc_status.last_calculated_crc = *crc;
    crc_status.calculation_count++;

    return HAL_OK;
}

