static HAL_StatusTypeDef CRC_ValidateConfig(const CRC_Config *config)
{
    if (config->polynomial == 0) {
        return HAL_ERROR;
    }

    if (config->input_format > CRC_FORMAT_32BIT ||
        config->output_format > CRC_FORMAT_32BIT) {
        return HAL_ERROR;
    }

    return HAL_OK;
}

/**
 * @brief Software CRC calculation for byte data
 * @param data Pointer to data buffer
 * @param size Size of data in bytes
 * @return uint32_t Calculated CRC value
 */
static uint32_t CRC_CalculateSoftware(const uint8_t *data, uint32_t size)
{
    uint32_t crc = current_config.init_value;
    uint32_t polynomial = current_config.polynomial;

    for (uint32_t i = 0; i < size; i++) {
        crc ^= (uint32_t)data[i] << CRC_SHIFT_24;

        for (uint8_t j = 0; j < CRC_BITS_PER_BYTE; j++) {
            if (crc & CRC_MSB_MASK) {
                crc = (crc << 1) ^ polynomial;
            } else {
                crc <<= 1;
            }
        }
    }

    return crc;
}

/**
 * @brief Software CRC calculation for 32-bit word data
 * @param data Pointer to 32-bit data array
 * @param size Number of 32-bit words
 * @return uint32_t Calculated CRC value
 */
static uint32_t CRC_CalculateSoftware32(const uint32_t *data, uint32_t size)
{
    uint32_t crc = current_config.init_value;
    uint32_t polynomial = current_config.polynomial;

    for (uint32_t i = 0; i < size; i++) {
        uint32_t word = data[i];

        if (current_config.input_reverse) {
            word = CRC_Reflect(word, CRC_BITS_PER_WORD);
        }

        crc ^= word;

        for (uint8_t j = 0; j < CRC_BITS_PER_WORD; j++) {
            if (crc & CRC_MSB_MASK) {
                crc = (crc << 1) ^ polynomial;
            } else {
                crc <<= 1;
            }
        }
    }

    if (current_config.output_reverse) {
        crc = CRC_Reflect(crc, CRC_BITS_PER_WORD);
    }

    return crc;
}

/**
 * @brief Reflect bits in a value
 * @param value Value to reflect
 * @param bits Number of bits to reflect
 * @return uint32_t Reflected value
 */
static uint32_t CRC_Reflect(uint32_t value, uint8_t bits)
{
    uint32_t reflected = 0;

    for (uint8_t i = 0; i < bits; i++) {
        if (value & (1U << i)) {
            reflected |= (1U << (bits - 1 - i));
        }
    }

    return reflected;
}

